void graph_swap_frame_thread_proc(void *arg)
{
    graph_thread_data_t *data = (graph_thread_data_t *)arg;

    while (1) {
        WaitSema(data->sema_swap);
        SwapBuffers();
        SignalSema(data->sema_done);
    }
}

